Code Good:
function processOrder(Order $order): OrderResult {
    if ($order->isCancelled()) {
        throw new OrderCancelledException($order->id);
    }
    if ($order->items->isEmpty()) {
        throw new EmptyOrderException($order->id);
    }
    if (!$order->user->hasValidPaymentMethod()) {
        throw new NoPaymentMethodException($order->user->id);
    }
    // Happy path - no nesting:
    $payment = $this->chargePayment($order);
    $this->updateInventory($order);
    $this->sendConfirmation($order);
    return new OrderResult($order, $payment);
}

Code Bad:
function processOrder(Order $order): OrderResult {
    if (!$order->isCancelled()) {
        if ($order->items->isNotEmpty()) {
            if ($order->user->hasValidPaymentMethod()) {
                $payment = $this->chargePayment($order);
                // More nesting...
            } else {
                throw new Exception('No payment');
            }
        } else {
            throw new Exception('Empty order');
        }
    } else {
        throw new Exception('Cancelled');
    }
}

